        "viz_DJJszJnH": {
            "type": "splunk.table",
            "title": "",
            "dataSources": {
                "primary": "ds_L8VFGMAl"
            },
            "options": {
                "count": 5,
                "showInternalFields": false,
                "columnFormat": {
                    "Severity": {
                        "data": "> table | seriesByName(\"Severity\") | formatByType(SeverityColumnFormatEditorConfig)",
                        "rowColors": "> table | seriesByName('Severity') | pick(SeverityRowColorsEditorConfig)",
                        "rowBackgroundColors": "> table | seriesByName(\"Severity\") | matchValue(SeverityRowBackgroundColorsEditorConfig)"
                    },
                    "Original Severity": {
                        "data": "> table | seriesByName(\"Original Severity\") | formatByType(Original_SeverityColumnFormatEditorConfig)",
                        "rowColors": "> table | seriesByName('Original Severity') | pick(Original_SeverityRowColorsEditorConfig)",
                        "rowBackgroundColors": "> table | seriesByName(\"Original Severity\") | matchValue(Original_SeverityRowBackgroundColorsEditorConfig)"
                    },
                    "Current Severity": {
                        "data": "> table | seriesByName(\"Current Severity\") | formatByType(Current_SeverityColumnFormatEditorConfig)",
                        "rowColors": "> table | seriesByName('Current Severity') | pick(Current_SeverityRowColorsEditorConfig)",
                        "rowBackgroundColors": "> table | seriesByName(\"Current Severity\") | matchValue(Current_SeverityRowBackgroundColorsEditorConfig)"
                    }
                }
            },
            "context": {
                "SeverityColumnFormatEditorConfig": {
                    "string": {
                        "unitPosition": "after"
                    }
                },
                "SeverityRowColorsEditorConfig": [
                    "#ffffff"
                ],
                "SeverityRowBackgroundColorsEditorConfig": [
                    {
                        "match": "Critical",
                        "value": "#D41F1F"
                    },
                    {
                        "match": "Warning",
                        "value": "#D94E17"
                    },
                    {
                        "match": "Info",
                        "value": "#CBA700"
                    },
                    {
                        "match": "Cleared",
                        "value": "#669922"
                    }
                ],
                "Original_SeverityColumnFormatEditorConfig": {
                    "string": {
                        "unitPosition": "after"
                    }
                },
                "Current_SeverityColumnFormatEditorConfig": {
                    "string": {
                        "unitPosition": "after"
                    }
                },
                "Original_SeverityRowColorsEditorConfig": [
                    "#ffffff"
                ],
                "Original_SeverityRowBackgroundColorsEditorConfig": [
                    {
                        "match": "Warning",
                        "value": "#ffa857"
                    },
                    {
                        "match": "Cleared",
                        "value": "#088f44"
                    },
                    {
                        "match": "Critical",
                        "value": "#fe3a3a"
                    },
                    {
                        "match": "Info",
                        "value": "#2EB82E"
                    }
                ],
                "Current_SeverityRowColorsEditorConfig": [
                    "#ffffff"
                ],
                "Current_SeverityRowBackgroundColorsEditorConfig": [
                    {
                        "match": "Critical",
                        "value": "#FE3A3A"
                    },
                    {
                        "match": "Info",
                        "value": "#2eb82e"
                    },
                    {
                        "match": "Cleared",
                        "value": "#088f44"
                    },
                    {
                        "match": "Warning",
                        "value": "#ff7149"
                    }
                ]
            },
            "description": "Displays detailed alarm records corresponding to the selected point or time range on the Alarms Over Time by Original Severity line chart, including alarm name, severity, category, affected device, timestamp, and status for in-depth analysis.",
            "hideWhenNoData": true
        },
