        "viz_z2DDYfUK": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_i8SkYEQ3_ds_LdVDy661"
            },
            "title": "Severity Increased",
            "options": {
                "majorColor": "#dc4e41",
                "trendColor": "#dc4e41",
                "backgroundColor": "#000000"
            },
            "eventHandlers": [
                {
                    "type": "drilldown.setToken",
                    "options": {
                        "tokens": [
                            {
                                "token": "clicked_single_value",
                                "value": "escalating"
                            }
                        ]
                    }
                }
            ],
            "description": "Alarms escalated to higher severity in selected time range"
