    },
    "dataSources": {
        "ds_nwma95it": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| eval Domain=coalesce(Domain,\"-\")\n| search Domain IN ($domain_name$)\n| join type=left AncestorMoId [\n    | inputlookup cisco_intersight_server_profiles\n    | eval AncestorMoId='AssignedServer.Moid'\n    | rename Name as ProfileName, Moid as ProfileMoid\n  ]\n| eval condition_check = case(\n    isnotnull(ProfileMoid) AND AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\"), 1,\n    isnull(ProfileMoid) AND NOT (AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\")) OR isnull(AncestorMoType), 1,\n    true(), 0\n)\n| eval keep = case(\n    \"$exclude_server_profile$\"=\"true\" AND condition_check=1, 1,\n    \"$exclude_server_profile$\"=\"false\", 1,\n    true(), 0\n)\n| where keep=1\n| stats count by Severity"
            },
            "name": "Severity Pie chart"
        },
        "ds_LdVDy661": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| eval Domain=coalesce(Domain,\"-\")\n| search Domain IN ($domain_name$)\n| where Acknowledge!=\"None\"\n| join type=left AncestorMoId [\n    | inputlookup cisco_intersight_server_profiles\n    | eval AncestorMoId='AssignedServer.Moid'\n    | rename Name as ProfileName, Moid as ProfileMoid\n  ]\n| eval condition_check = case(\n    isnotnull(ProfileMoid) AND AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\"), 1,\n    isnull(ProfileMoid) AND NOT (AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\")) OR isnull(AncestorMoType), 1,\n    true(), 0\n)\n| eval keep = case(\n    \"$exclude_server_profile$\"=\"true\" AND condition_check=1, 1,\n    \"$exclude_server_profile$\"=\"false\", 1,\n    true(), 0\n)\n| where keep=1\n| stats count"
            },
            "name": "Escalating Alarms"
        },
        "ds_ngWKAs6v": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| eval Domain=coalesce(Domain,\"-\")\n| search Domain IN ($domain_name$)\n| where Severity != \"Cleared\"\n| where Acknowledge == \"None\"\n| where Suppressed == \"false\"\n| join type=left AncestorMoId [\n    | inputlookup cisco_intersight_server_profiles\n    | eval AncestorMoId='AssignedServer.Moid'\n    | rename Name as ProfileName, Moid as ProfileMoid\n  ]\n| eval condition_check = case(\n    isnotnull(ProfileMoid) AND AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\"), 1,\n    isnull(ProfileMoid) AND NOT (AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\")) OR isnull(AncestorMoType), 1,\n    true(), 0\n)\n| eval keep = case(\n    \"$exclude_server_profile$\"=\"true\" AND condition_check=1, 1,\n    \"$exclude_server_profile$\"=\"false\", 1,\n    true(), 0\n)\n| where keep=1\n| stats count"
            },
            "name": "Active Alarms"
        },
        "ds_CBph9myb": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| eval Domain=coalesce(Domain,\"-\")\n| search Domain IN ($domain_name$)\n| where Severity = \"Cleared\"\n| join type=left AncestorMoId [\n    | inputlookup cisco_intersight_server_profiles\n    | eval AncestorMoId='AssignedServer.Moid'\n    | rename Name as ProfileName, Moid as ProfileMoid\n  ]\n| eval condition_check = case(\n    isnotnull(ProfileMoid) AND AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\"), 1,\n    isnull(ProfileMoid) AND NOT (AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\")) OR isnull(AncestorMoType), 1,\n    true(), 0\n)\n| eval keep = case(\n    \"$exclude_server_profile$\"=\"true\" AND condition_check=1, 1,\n    \"$exclude_server_profile$\"=\"false\", 1,\n    true(), 0\n)\n| where keep=1\n| stats count"
            },
            "name": "Cleared Alarms"
        },
        "ds_QTll4kTz": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| eval Domain=coalesce(Domain,\"-\")\n| search Domain IN ($domain_name$)\n| join type=left AncestorMoId [\n    | inputlookup cisco_intersight_server_profiles\n    | eval AncestorMoId='AssignedServer.Moid'\n    | rename Name as ProfileName, Moid as ProfileMoid\n  ]\n| eval condition_check = case(\n    isnotnull(ProfileMoid) AND AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\"), 1,\n    isnull(ProfileMoid) AND NOT (AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\")) OR isnull(AncestorMoType), 1,\n    true(), 0\n)\n| eval keep = case(\n    \"$exclude_server_profile$\"=\"true\" AND condition_check=1, 1,\n    \"$exclude_server_profile$\"=\"false\", 1,\n    true(), 0\n)\n| where keep=1\n| stats count by Name\n| sort count desc"
            },
            "name": "Alarm by Categories"
        },
        "ds_hTf62YF3": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| eval Domain=coalesce(Domain,\"-\")\n| search Domain IN ($domain_name$)\n| eval OrigSeverityCode = case(\n    OrigSeverity=\"Cleared\", 0,\n    OrigSeverity=\"Info\", 1,\n    OrigSeverity=\"Warning\", 2,\n    OrigSeverity=\"Critical\", 3\n)\n| eval SeverityCode = case(\n    Severity=\"Cleared\", 0,\n    Severity=\"Info\", 1,\n    Severity=\"Warning\", 2,\n    Severity=\"Critical\", 3\n)\n| sort SeverityCode desc\n| eval keep = case(\n    \"$clicked_single_value$\"=\"active\" AND Severity!=\"Cleared\" AND Acknowledge == \"None\" AND Suppressed == \"false\", 1,\n    \"$clicked_single_value$\"=\"cleared\" AND Severity=\"Cleared\", 1,\n    \"$clicked_single_value$\"=\"suppressed\" AND Suppressed!=\"false\", 1,\n    \"$clicked_single_value$\"=\"acknowledged\" AND Acknowledge!=\"None\", 1,\n    \"$clicked_single_value$\"=\"escalating\" AND OrigSeverityCode < SeverityCode, 1,\n    true(), 0\n)\n| where keep=1\n| rename AffectedMo.ObjectType as \"Affected Object Type\", AffectedMoDisplayName as \"Affected Object\"\n| search $drilldown_table_search$\n| join type=left AncestorMoId [\n    | inputlookup cisco_intersight_server_profiles\n    | eval AncestorMoId='AssignedServer.Moid'\n    | rename Name as ProfileName, Moid as ProfileMoid\n  ]\n| eval condition_check = case(\n    isnotnull(ProfileMoid) AND AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\"), 1,\n    isnull(ProfileMoid) AND NOT (AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\")) OR isnull(AncestorMoType), 1,\n    true(), 0\n)\n| eval keep = case(\n    \"$exclude_server_profile$\"=\"true\" AND condition_check=1, 1,\n    \"$exclude_server_profile$\"=\"false\", 1,\n    true(), 0\n)\n| where keep=1\n| table Name, Description, Severity, ModTime, \"Affected Object\", \"Affected Object Type\", Suppressed, Acknowledge, AcknowledgeBy"
            },
            "name": "Drilldown table for Single value panels"
        },
        "ds_Y34F3mG3": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| eval Domain=coalesce(Domain,\"-\")\n| search Domain IN ($domain_name$)\n| eval keep = case(\n    \"$clicked_pie_chart$\"=\"severity\" AND \"$alarm_severity$\"==\"None\" AND Severity!=\"Cleared\", 1,\n    \"$clicked_pie_chart$\"=\"severity\" AND Severity=\"$alarm_severity$\", 1,\n    \"$clicked_pie_chart$\"=\"name\" AND Name=\"$alarm_category$\", 1,\n    true(), 0\n)\n| where keep=1\n| eval SeverityCode = case(\n    Severity=\"Cleared\", 0,\n    Severity=\"Info\", 1,\n    Severity=\"Warning\", 2,\n    Severity=\"Critical\", 3\n)\n| sort SeverityCode desc\n| rename AffectedMo.ObjectType as \"Affected Object Type\", AffectedMoDisplayName as \"Affected Object\"\n| search $drilldown_table_search1$\n| join type=left AncestorMoId [\n    | inputlookup cisco_intersight_server_profiles\n    | eval AncestorMoId='AssignedServer.Moid'\n    | rename Name as ProfileName, Moid as ProfileMoid\n  ]\n| eval condition_check = case(\n    isnotnull(ProfileMoid) AND AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\"), 1,\n    isnull(ProfileMoid) AND NOT (AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\")) OR isnull(AncestorMoType), 1,\n    true(), 0\n)\n| eval keep = case(\n    \"$exclude_server_profile$\"=\"true\" AND condition_check=1, 1,\n    \"$exclude_server_profile$\"=\"false\", 1,\n    true(), 0\n)\n| where keep=1\n| table Name, Description, Severity, ModTime, \"Affected Object\", \"Affected Object Type\", Suppressed, Acknowledge, AcknowledgeBy"
