                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| eval Domain=coalesce(Domain,\"-\")\n| search Domain IN ($domain_name$)\n| eval OrigSeverityCode = case(\n    OrigSeverity=\"Cleared\", 0,\n    OrigSeverity=\"Info\", 1,\n    OrigSeverity=\"Warning\", 2,\n    OrigSeverity=\"Critical\", 3\n)\n| eval SeverityCode = case(\n    Severity=\"Cleared\", 0,\n    Severity=\"Info\", 1,\n    Severity=\"Warning\", 2,\n    Severity=\"Critical\", 3\n)\n| where OrigSeverityCode < SeverityCode\n| join type=left AncestorMoId [\n    | inputlookup cisco_intersight_server_profiles\n    | eval AncestorMoId='AssignedServer.Moid'\n    | rename Name as ProfileName, Moid as ProfileMoid\n  ]\n| eval condition_check = case(\n    isnotnull(ProfileMoid) AND AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\"), 1,\n    isnull(ProfileMoid) AND NOT (AncestorMoType IN (\"compute.Blade\",\"compute.RackUnit\")) OR isnull(AncestorMoType), 1,\n    true(), 0\n)\n| eval keep = case(\n    \"$exclude_server_profile$\"=\"true\" AND condition_check=1, 1,\n    \"$exclude_server_profile$\"=\"false\", 1,\n    true(), 0\n)\n| where keep=1\n| stats count"
