        "ds_wURnJWW2": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_Severity) as Severity, latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_AffectedMoDisplayName), latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_Name) as Name from datamodel=Cisco_Intersight where nodename=cisco_intersight.cisco_intersight_condAlarms AND \ncisco_intersight.cisco_intersight_condAlarms.condAlarms_AccountName IN ($account_name$)\nAND cisco_intersight.cisco_intersight_condAlarms.condAlarms_Suppressed=False by cisco_intersight.cisco_intersight_condAlarms.condAlarms_Moid, cisco_intersight.cisco_intersight_condAlarms.condAlarms_AffectedMoDisplayName, cisco_intersight.cisco_intersight_condAlarms.condAlarms_Severity, cisco_intersight.cisco_intersight_condAlarms.condAlarms_AccountName\n| rename cisco_intersight.cisco_intersight_condAlarms.condAlarms_AffectedMoDisplayName as AffectedMoDisplayName\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\" \n| chart count by Domain, Severity \n| search Domain=\"$domain_name$\"\n| rename Domain as \"Intersight Domain\"\n| fillnull value=0 Critical Warning Info Cleared\n| table \"Intersight Domain\" Critical Warning Info Cleared"
            },
            "name": "Server Alarms Status"
        },
        "ds_vC3RIOfw": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_Name) as Name latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_ModTime) as \"Last Modification Time\" latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_OrigSeverity) as \"Original Severity\" latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_Severity) as \"Current Severity\" latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_CreationTime) as \"Alarm Creation Time\" latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_AffectedMoDisplayName) as \"Affected Object\" latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_Description) as Description latest(cisco_intersight.cisco_intersight_condAlarms.condAlarms_AcknowledgeBy) as \"Acknowledged By\" from datamodel=Cisco_Intersight where nodename=cisco_intersight.cisco_intersight_condAlarms AND cisco_intersight.cisco_intersight_condAlarms.condAlarms_AffectedMoDisplayName=\"*$alarm_domain$*\" AND (cisco_intersight.cisco_intersight_condAlarms.condAlarms_Severity=\"Warning\" OR cisco_intersight.cisco_intersight_condAlarms.condAlarms_Severity=\"Critical\") by cisco_intersight.cisco_intersight_condAlarms.condAlarms_Moid, cisco_intersight.cisco_intersight_condAlarms.condAlarms_Suppressed\n| where ('Current Severity'=case(\"$alarm_severity$\"==\"Warning\", \"Warning\", \"$alarm_severity$\"==\"Critical\", \"Critical\", true(), \"Warning\") OR 'Current Severity'=case(\"$alarm_severity$\"==\"Warning\", \"Warning\", \"$alarm_severity$\"==\"Critical\", \"Critical\", true(), \"Critical\"))\n| rename cisco_intersight.cisco_intersight_condAlarms.condAlarms_Moid as \"Alarm ID\", cisco_intersight.cisco_intersight_condAlarms.condAlarms_Suppressed as \"Suppressed\"\n| table \"Alarm ID\", Description, \"Affected Object\", \"Original Severity\", \"Current Severity\", \"Alarm Creation Time\", \"Acknowledged By\", \"Last Modification Time\", \"Suppressed\""
            },
            "name": "Server Alarms Status - Drilldown Table"
        },
        "ds_4T8LpDCn": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "query": "| inputlookup cisco_intersight_compute_bladeidentities | where splunk_managed_lifecycle == \"PRESENT\"\n      | search account_name IN ($account_name$)\n      | dedup RegisteredDevice.Moid\n      | rename RegisteredDevice.Moid as DeviceMoId \n      | rename RegisteredDevice.DeviceHostname as DeviceHostname \n      | where isnotnull(DeviceHostname) \n      | table DeviceMoId, DeviceHostname "
            },
            "name": "Intersight Domain name filter"
        },
        "ds_AgerbtAk": {
