                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\"\n| search account_name IN ($account_name$)\n| rex field=AffectedMoDisplayName \"^(?<Domain>[^\\/]*)\"\n| search Domain IN ($domain_name$)\n| eval CreationEpoch = strptime(CreationTime, \"%Y-%m-%dT%H:%M:%S.%3NZ\")\n| eval x_days_ago = now() - ($x_days$*24*60*60)\n| where CreationEpoch < x_days_ago AND Severity!=\"Cleared\" AND Suppressed=\"false\" AND Acknowledge=\"None\"\n| table Severity"
            },
